+func mergeScopes(scopes []string, extras []string) []string {
+	set := make(map[string]struct{}, len(scopes)+len(extras))
+
+	for _, s := range scopes {
+		if s == "" {
+			continue
+		}
+
+		set[s] = struct{}{}
+	}
+
+	for _, s := range extras {
+		if s == "" {
+			continue
+		}
+
+		set[s] = struct{}{}
+	}
+
+	out := make([]string, 0, len(set))
+	for s := range set {
+		out = append(out, s)
+	}
+
+	sort.Strings(out)
+
+	return out
+}
